func formatStatus(status string) string {
	switch status {
	case "watching":
		return "watching"
	case "completed":
		return "completed"
	case "on_hold":
		return "on hold"
	case "dropped":
		return "dropped"
	case "plan_to_watch":
		return "plan to watch"
	default:
		return status
	}
}

